function.body:
vResult VARCHAR2(2000) := ''; vCollectionTransit RECORD; vPaymentMethod RECORD; vOrg RECORD; vRecord RECORD; vDocumentNo VARCHAR2(32); vPayment RECORD; vPaymentDetailID VARCHAR2(32); vPaymentScheduleDetailID VARCHAR2(32); vInvoice RECORD; vPaymentSchedule RECORD; vInvoices VARCHAR2(2000) := 'Factura Nº: '; vStatus VARCHAR2(60); vDescription VARCHAR2(1000) := 'CeT '; vCheque NUMBER; vPending RECORD; v_DatePaid DATE; --OBTG:VARCHAR2--
BEGIN BEGIN -- Cobro en transito SELECT * INTO vCollectionTransit FROM sspitra_collectiontransit WHERE sspitra_collectiontransit_id = vRecordID;
-- Metodo de pago SELECT * INTO vPaymentMethod FROM fin_paymentmethod WHERE fin_paymentmethod_id = vCollectionTransit.fin_paymentmethod_id; IF vPaymentMethod.em_sspitra_doctype_id IS NULL THEN RAISE_APPLICATION_ERROR(-20000, 'No existe tipo de documento configurado para el metodo de pago '||vPaymentMethod.name); END IF;
-- Organizacion SELECT * INTO vOrg FROM ad_org WHERE ad_org_id = vCollectionTransit.ad_org_id;
-- Numero de documento para el cobro IF REPLACE(COALESCE(vCollectionTransit.payment_documentno,''),' ','') != '' THEN SELECT COUNT(*) INTO vCheque FROM FIN_PaymentMethod WHERE name ILIKE '%CHEQUE%' AND FIN_PaymentMethod_ID = vCollectionTransit.fin_paymentmethod_id; IF vCheque > 0 THEN vDocumentNo := vCollectionTransit.payment_documentno||'/'||vCollectionTransit.check_account; ELSE vDocumentNo := vCollectionTransit.payment_documentno; END IF; ELSE ad_sequence_doctype(vPaymentMethod.em_sspitra_doctype_id, vOrg.ad_client_id, 'Y', vDocumentNo); END IF;
-- Cobro INSERT INTO fin_payment ( fin_payment_id, ad_client_id, ad_org_id, createdby, updatedby, isreceipt, c_currency_id, fin_paymentmethod_id, documentno, paymentdate, fin_financial_account_id, c_doctype_id, status, c_bpartner_id, amount, em_ssior_detailreport, em_aprm_reconcile_payment, em_aprm_executepayment, em_aprm_add_scheduledpayments, finacc_txn_amount, description, referenceno, em_sspac_checkacc, em_sspac_c_bpartner_id, em_ecscap_banktransfer_id, em_ecscap_deposit ) VALUES ( get_uuid(), vOrg.ad_client_id, vOrg.ad_org_id, vUserID, vUserID, 'Y', vCollectionTransit.c_currency_id, vCollectionTransit.fin_paymentmethod_id, vDocumentNo, vCollectionTransit.paymentdate, vCollectionTransit.fin_financial_account_id, vPaymentMethod.em_sspitra_doctype_id, 'RPAP', vCollectionTransit.c_bpartner_id, vCollectionTransit.amount, 'Y', 'N', 'N', 'N', vCollectionTransit.amount, vCollectionTransit.description, vCollectionTransit.referenceno, vCollectionTransit.check_account, vCollectionTransit.charged_by, vCollectionTransit.ssfi_banktransfer_id, vCollectionTransit.deposit ) RETURNING * INTO vPayment;
FOR vRecord IN ( SELECT * FROM sspitra_ct_detail WHERE sspitra_collectiontransit_id = vRecordID ) LOOP -- Factura SELECT * INTO vInvoice FROM c_invoice WHERE c_invoice_id = vRecord.c_invoice_id;
--Validacion IF vRecord.amount > vInvoice.outstandingamt THEN RAISE EXCEPTION '%', 'La factura '||vInvoice.documentno||' posee un monto pendiente ('||vInvoice.outstandingamt ||') inferior al que se quiere pagar ('||vRecord.amount||')'; --OBTG:-20000-- END IF;
-- Concatenamos para la descripcion vDescription := vDescription||vInvoice.documentno||' ';
-- Cuota SELECT * INTO vPaymentSchedule FROM fin_payment_schedule WHERE fin_payment_schedule_id = vRecord.fin_payment_schedule_id;
--Validacion IF vPaymentSchedule.fin_payment_schedule_id IS NULL THEN RAISE_APPLICATION_ERROR(-20000, 'Error al intentar obtener la cuota de la factura '||vInvoice.documentno); END IF; IF vRecord.amount > vPaymentSchedule.outstandingamt THEN RAISE EXCEPTION '%', 'La cuota '||vPaymentSchedule.duedate::DATE||' posee un monto pendiente ('||vPaymentSchedule.outstandingamt ||') inferior al que se quiere pagar ('||vRecord.amount||')'; --OBTG:-20000-- END IF;
-- Creamos el detalle de pago INSERT INTO fin_payment_detail ( fin_payment_detail_id, ad_client_id, ad_org_id, createdby, updatedby, fin_payment_id, amount, refund ) values( get_uuid(), vPayment.ad_client_id, vPayment.ad_org_id, vPayment.createdby, vPayment.updatedby, vPayment.fin_payment_id, vRecord.amount, 'N' ) RETURNING fin_payment_detail_id INTO vPaymentDetailID;
-- Linea del monto pendiente SELECT * INTO vPending FROM fin_payment_scheduledetail WHERE fin_payment_schedule_invoice = vPaymentSchedule.fin_payment_schedule_id AND isinvoicepaid = 'N' AND amount > 0 ORDER BY amount LIMIT 1;
IF vPending.amount - vRecord.amount = 0 THEN DELETE FROM fin_payment_scheduledetail WHERE fin_payment_scheduledetail_id = vPending.fin_payment_scheduledetail_id; ELSE UPDATE fin_payment_scheduledetail SET amount = amount - vRecord.amount WHERE fin_payment_scheduledetail_id = vPending.fin_payment_scheduledetail_id; END IF;
INSERT INTO fin_payment_scheduledetail ( fin_payment_scheduledetail_id, ad_client_id, ad_org_id, createdby, updatedby, fin_payment_detail_id, fin_payment_schedule_invoice, fin_payment_schedule_order, amount, c_bpartner_id, isinvoicepaid, em_sspitra_ct_detail_id ) values( get_uuid(), vPayment.ad_client_id, vPayment.ad_org_id, vPayment.createdby, vPayment.updatedby, vPaymentDetailID, vPaymentSchedule.fin_payment_schedule_id, vPending.fin_payment_schedule_order, vRecord.amount, vCollectionTransit.c_bpartner_id, 'Y', vRecord.sspitra_ct_detail_id ) RETURNING fin_payment_scheduledetail_id INTO vPaymentScheduleDetailID;
-- Monto pendiente de la cuota UPDATE fin_payment_schedule SET paidamt = paidamt + vRecord.amount, outstandingamt = outstandingamt - vRecord.amount WHERE fin_payment_schedule_id = vPaymentSchedule.fin_payment_schedule_id;
-- Monto pendiente de la factura IF vInvoice.outstandingamt - vRecord.amount = 0 THEN
select TO_DATE(to_char(max(fp.paymentdate),'dd/MM/yyyy')) as date_paid into v_DatePaid from fin_payment_scheduledetail fpsd join fin_payment_Detail fpd on fpd.fin_payment_detail_id = fpsd.fin_payment_detail_id join fin_payment fp on fp.fin_payment_id = fpd.fin_payment_id where exists (select 1 from fin_payment_schedule fps where fps.c_invoice_id = vInvoice.c_invoice_id and fps.fin_payment_schedule_id = fpsd.fin_payment_schedule_invoice );
UPDATE c_invoice SET ispaid = 'Y', totalpaid = totalpaid + vRecord.amount, outstandingamt = outstandingamt - vRecord.amount , Finalsettlement = v_DatePaid WHERE c_invoice_id = vInvoice.c_invoice_id; ELSE UPDATE c_invoice SET totalpaid = totalpaid + vRecord.amount, outstandingamt = outstandingamt - vRecord.amount WHERE c_invoice_id = vInvoice.c_invoice_id; END IF;
-- Concatenamos la factura vInvoices := vInvoices||vInvoice.documentno||', '; END LOOP;
-- Estado del cobro vStatus := 'RPR';
-- Transaccion IF vCollectionTransit.onlypayment = 'N' THEN vStatus := 'RDNC';
INSERT INTO fin_finacc_transaction ( fin_finacc_transaction_id, ad_client_id, ad_org_id, createdby, updatedby, c_currency_id, fin_financial_account_id, line, fin_payment_id, dateacct, status, depositamt, processed, trxtype, statementdate, description, c_bpartner_id, em_aprm_processed ) VALUES ( get_uuid(), vPayment.ad_client_id, vPayment.ad_org_id, vPayment.createdby, vPayment.updatedby, vPayment.c_currency_id, vPayment.fin_financial_account_id, (SELECT COALESCE(MAX(line),0)+10 FROM fin_finacc_transaction WHERE fin_financial_account_id=vPayment.fin_financial_account_id), vPayment.fin_payment_id, now(), 'RDNC', vPayment.amount, 'Y', 'BPD', now(), vInvoices, vPayment.c_bpartner_id, 'R' );
-- Cuenta financiera UPDATE fin_financial_account SET currentbalance = currentbalance + vPayment.amount WHERE fin_financial_account_id = vPayment.fin_financial_account_id;
END IF;
-- Actualizamos el cobro UPDATE fin_payment SET status = vStatus, em_aprm_process_payment = 'RE', processed = 'Y', description = substring(vDescription from 1 for 255) WHERE fin_payment_id = vPayment.fin_payment_id;
-- Actualizamos el cobro en transito UPDATE sspitra_collectiontransit SET fin_payment_id = vPayment.fin_payment_id, status = 'P' WHERE sspitra_collectiontransit_id = vRecordID;
RETURN 'OK'; END;
EXCEPTION WHEN OTHERS THEN RETURN SQLERRM; END SSPITRA_CREATEPAYMENT
